import sys, json

data = json.load(sys.stdin)
json.dump(data, open('after-cpm-packages.json', 'w'), indent=2)

# Compare
baseline = json.load(open('baseline-packages.json'))
after = data

def extract(d):
    result = {}
    for proj in d.get('projects', []):
        name = proj['path'].split('/')[-1]
        pkgs = {}
        for fw in proj.get('frameworks', []):
            for p in fw.get('topLevelPackages', []):
                pkgs[p['id']] = p['resolvedVersion']
        result[name] = pkgs
    return result

b = extract(baseline)
a = extract(after)

changes = []
unchanged = []
for proj in sorted(set(list(b.keys()) + list(a.keys()))):
    bp = b.get(proj, {})
    ap = a.get(proj, {})
    for pkg in sorted(set(list(bp.keys()) + list(ap.keys()))):
        bv = bp.get(pkg, '-')
        av = ap.get(pkg, '-')
        if bv != av:
            changes.append((proj, pkg, bv, av))
        else:
            unchanged.append((proj, pkg, bv))

print('=== CHANGES ===')
for proj, pkg, bv, av in changes:
    print(f'  {proj}: {pkg} {bv} -> {av}')
if not changes:
    print('  (none)')

print(f'\n=== UNCHANGED: {len(unchanged)} packages ===')
"

